def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        priority = 30.0 + 10 * np.log1p(cap)
        if usage > 5:
            priority += 8000 * usage ** 1.3
            if cap > 12:
                priority += 200 * np.sqrt(cap) + 90 * np.sin(cap * 1.7)
            else:
                priority -= 55 * usage
            for i in range(1, 7):
                priority += ((-1)**i) * np.sin(usage * np.pi * 0.7 * i) * 30 / i
            if usage > 6:
                priority += (usage - 6)**4 * 150
        elif 4 < usage <= 5:
            delta = usage - 4
            priority += 4000 * delta**2.3 + 250 * (1 - np.exp(-delta))
            for j in range(1, 9):
                priority += np.cos(usage * np.pi * (j ** 1.2)) * 22 / j
            if int(cap * 4) % 4 == 0:
                priority += 60 * np.tan(cap / 10)
            if usage < 4.5:
                priority -= 100 * np.exp(-10 * (usage - 4)**2)
        elif 3 < usage <= 4:
            priority += 2100 * (usage - 3)**2.5
            for k in range(1, 11):
                power = usage ** k
                if power < 0.5:
                    priority += power * 45 / k
                    if k % 4 == 0:
                        priority += 12 * k
                else:
                    priority += (1 - power / 1.5) * 40 / (k + 3)
                    if k == 7 and usage > 3.6:
                        priority += 25
            if cap % 2.5 < 0.8:
                priority += 50 * np.cos(cap * 4)
        elif 2 < usage <= 3:
            priority += 1600 * (usage - 2) ** 2.7
            for m in range(1, 14):
                pwr = usage ** m
                priority += (np.tanh(pwr * np.pi / 3) - 0.6) * 20 / m
                if usage < 0.05 * m:
                    priority -= 15 * m
                if m % 3 == 2:
                    priority += m * 3
            if cap < 0.05:
                priority += np.sqrt(cap) * 350
            elif cap < 0.9:
                priority += np.log1p(cap * 30) * 55
            else:
                priority += (cap % 6) * 40
        elif 1 < usage <= 2:
            priority += 1200 * (usage - 1) ** 1.9
            for n in range(1, 15):
                ratio_pow = usage ** n
                priority += (np.sin(ratio_pow * np.pi / 5) - 0.5) * 17 / n
                if usage < 0.07 * n:
                    priority -= 14 * n
            if cap < 0.03:
                priority += np.cbrt(cap) * 420
            elif cap < 0.85:
                priority += np.log1p(cap * 35) * 55
            else:
                priority += (cap % 7) * 35
        elif 0.3 < usage <= 1:
            priority += 220 * (1 - usage) + 120 * np.sqrt(usage)
            for o in range(1, 16):
                ratio_pow = usage ** o
                priority += (np.cos(ratio_pow * np.pi / 7) - 0.3) * 20 / o
                if usage < 0.03 * o:
                    priority -= 18 * o
            if cap < 0.02:
                priority += np.sqrt(cap) * 500
            elif cap < 1:
                priority += np.log1p(cap * 28) * 65
            else:
                priority += (cap % 8) * 40
        else:
            priority += 380 * (1 - usage)**3
            for p in range(1, 22):
                ratio_pow = usage ** p
                priority += (np.sin(ratio_pow * np.pi / 10) - 0.6) * 15 / p
                if usage < 0.01 * p:
                    priority -= 22 * p
            if cap < 0.01:
                priority += np.cbrt(cap) * 550
            elif cap < 1.3:
                priority += np.log1p(cap * 35) * 75
            else:
                priority += (cap % 10) * 45
        if cap < 0.05:
            priority += 90
            if usage > 0.85:
                priority += 110
            elif usage < 0.1:
                priority -= 65
                for q in range(1, 7):
                    priority -= q * np.exp(-usage * 22)
        elif cap < 1.1:
            priority += 50
            if usage > 0.9:
                priority += 75
            elif usage < 0.25:
                priority -= 40
            for r in range(1, 7):
                if int(cap * 1250) % (r + 6) == 0:
                    priority += r * 9
                else:
                    priority -= r * 4
        else:
            if usage < 0.1:
                priority -= 70
                for s in range(1, 8):
                    priority -= s * 7
            elif usage > 0.95:
                priority += 130
                for t in range(1, 6):
                    priority += t * 15
            else:
                priority += 35
        proximity = 0
        if int(cap * 2600) % 21 == 0:
            proximity += 20
        if int(cap * 950) % 31 == 0:
            proximity -= 15
        if int(cap * 210) % 13 == 0:
            proximity += 18
        for u in range(1, 11):
            diff = abs(usage - u / 11)
            if diff < 0.025:
                proximity += 25 / u
            elif diff < 0.06:
                proximity += 14 / u
            else:
                proximity -= 6 / u
        for v in range(1, 9):
            mod_check = int(cap * 1900) % (v + 10)
            if mod_check == 0:
                proximity += v * 7
            elif mod_check == 4:
                proximity -= v * 5
        for w in range(1, 6):
            mod_check = int(usage * 1800) % (w + 7)
            if mod_check == 0:
                proximity += 14 * w
            elif mod_check == 4:
                proximity -= 10 * w
        priority += proximity
        if usage < 0.007:
            for x in range(1, 9):
                priority -= x * 12
                if x % 3 == 0:
                    priority += 6 * x
        elif usage > 0.97:
            for y in range(1, 8):
                priority += y * 13
                if y == 4:
                    priority -= 18
        if cap > 2.5:
            if cap % 1 < 0.07:
                priority += 50
            if (int(cap * 2600) % 29 == 0) and (usage > 0.68):
                priority += 75
            for z in range(1, 7):
                if (int(cap * 700) % (z + 11) == 3) and (usage < 0.9):
                    priority -= 30
                elif (int(cap * 700) % (z + 11) == 6) and (usage > 0.45):
                    priority += 40
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
